import{_ as e,o as i,c as r,ai as t,b5 as l}from"./chunks/framework.LAMr6Wp9.js";const f=JSON.parse('{"title":"软件设计","description":"","frontmatter":{"title":"软件设计","order":20},"headers":[],"relativePath":"design/index.md","filePath":"design/index.md"}'),n={name:"design/index.md"};function s(p,a,o,d,c,_){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="软件设计" tabindex="-1">软件设计 <a class="header-anchor" href="#软件设计" aria-label="Permalink to “软件设计”">​</a></h1><p>软件设计的基础意义是根据实际的业务需求编写软件进行实现。但是，在实际的环境中，事情往往没有想象中的那么简单，我们需要额外面临更多考验。例如：可行性问题、成本问题、可维护问题、质量问题等。如何解决这些附加问题是研究软件设计的根本动力。</p><h2 id="理论概览" tabindex="-1">理论概览 <a class="header-anchor" href="#理论概览" aria-label="Permalink to “理论概览”">​</a></h2><p>在众多的<a href="./typical/">经典范式</a>理论中，我们感到了百家争鸣般的喧闹。有的是宏观理论，为我们提供方向性指导，有的是专精细分领域，为不同的领域提出可实践的意见。</p><p>成熟大派，更是在特殊的领域内独占山头，为开发者提供一个稳定的栖息之地：</p><ul><li><a href="./oop/">面向对象编程</a></li><li><a href="./fp/">函数式编程</a></li><li><a href="./concurrent/">并发编程</a></li><li><a href="./async/">异步编程</a></li></ul><p><img src="'+l+'" alt=""></p><p>笔者总结<a href="./spacetime/">面向时空</a>是为了破除这些理论的隔阂，从一个更高更全面的维度去理解这些理论的本质，总结概括杂乱的理论商品，减少选择困难。并走到实践中去，提出具体的实践方案，让理论变得可行。</p><p>对于任意一个 IT 行业的技术，我们在学习它的时候，可以从使用者和实现者两个层面去学习，如果我们只是简单使用，那么可以从使用者的角度上去学习，如果我们需要自定义它，那么我们需要从实现者的角度上去学习。以此角度，一个人对于一个技术的掌握程度可以分为</p><ul><li>使用：作为技术的使用者，掌握基础的使用方法</li><li>调优：作为技术的深度使用者，初步理解了其外观结构，能够根据实际业务进行调优</li><li>设计：作为技术的设计者，整体掌握了技术的架构</li><li>实现：作为技术的实现者，整体掌握技术架构，并且熟悉技术实现中的特定细节</li></ul><p>某个技术点，如果市面上存在着多个同类型的技术或者解决方案，那么作为其使用者，考虑<strong>如何选型</strong>是最基础的考量。</p>',11)])])}const m=e(n,[["render",s]]);export{f as __pageData,m as default};
